
import numpy as np
import pandas as pd
import matplotlib.pyplot as plt
np.random.seed(42) 
customer_ages = np.random.randint(18, 70, size=50)
purchase_amounts = np.random.uniform(10, 100, size=50)

data = {
    'Customer Age': customer_ages,
    'Purchase Amount': purchase_amounts
}
df = pd.DataFrame(data)

max_spending_customer = df[df['Purchase Amount'] == df['Purchase Amount'].max()]
highest_spender_name = max_spending_customer['Customer Age'].values[0]
highest_spender_amount = max_spending_customer['Purchase Amount'].values[0]

print(f"Highest Spender: Customer {highest_spender_name}, Purchase Amount: ${highest_spender_amount:.2f}")

average_spending_by_age = df.groupby('Customer Age')['Purchase Amount'].mean()
average_spending_by_age = average_spending_by_age.round(2)  

print("\nAverage Spending by Age Group:")
print(average_spending_by_age)

total_purchase_amount = df['Purchase Amount'].sum()

above_average_spending_customers = df[df['Purchase Amount'] > average_spending_by_age.max()]
num_above_average_spending_customers = len(above_average_spending_customers)

print(f"\nNumber of Customers Spending Above Average: {num_above_average_spending_customers}")

print("\nCustomers Spending Above Average:")
print(above_average_spending_customers)

plt.figure(figsize=(10, 6))
plt.scatter(df['Customer Age'], df['Purchase Amount'])
plt.title('Scatter Plot of Customer Ages vs Purchase Amount')
plt.xlabel('Customer Age')
plt.ylabel('Purchase Amount')
plt.grid(True)
plt.show()

age_bins = np.arange(18, 72, 5) 
average_spending_by_age_binned = df.groupby(pd.cut(df['Customer Age'], bins=age_bins))['Purchase Amount'].mean()

plt.figure(figsize=(10, 6))
average_spending_by_age_binned.plot(kind='bar')
plt.title('Average Spending by Age Group')
plt.xlabel('Age Group')
plt.ylabel('Average Purchase Amount')
plt.xticks(rotation=45)
plt.grid(True)
plt.show()

